using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "MyMcpServer", Version = "1.0.0" };
    })
    .WithHttpTransport()
    .WithTools<WeatherTools>()
    .WithResources<ConfigResources>();

var app = builder.Build();

app.MapMcp();

app.Run();

// ---------- Tools ----------

[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool(Name = "get_weather", Title = "Get Weather",
        ReadOnly = true, Idempotent = true)]
    public static string GetWeather(string city)
    {
        // Stub — replace with a real weather API call.
        return $"{{\"city\":\"{city}\",\"temp_f\":72,\"condition\":\"Sunny\"}}";
    }
}

// ---------- Resources ----------

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "app_settings",
        Title = "Application Settings", MimeType = "application/json")]
    public static string GetAppSettings()
    {
        return """
        {
            "featureFlags": { "darkMode": true, "betaAccess": false },
            "limits": { "maxRequests": 1000, "timeoutMs": 5000 }
        }
        """;
    }

    [McpServerResource(UriTemplate = "config://app/version", Name = "app_version",
        Title = "Application Version", MimeType = "text/plain")]
    public static string GetAppVersion()
    {
        return "1.0.0";
    }
}

